function getBrowserInfo() {
  var ua = navigator.userAgent;
  var langs = navigator.languages ? navigator.languages.join(', ') : (navigator.language || '未知');
  var plat = navigator.platform || '未知';
  var cores = navigator.hardwareConcurrency || '未知';
  var mem = navigator.deviceMemory ? navigator.deviceMemory + ' GB' : '不支持';
  var gpu = '检测中...';
  var canvas = document.createElement('canvas');
  var gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
  if (gl && gl.getParameter) {
    var di = gl.getExtension('WEBGL_debug_renderer_info');
    gpu = di ? gl.getParameter(di.UNMASKED_RENDERER_WEBGL) : 'WebGL可用但信息受限';
  }
  var conn = navigator.connection || navigator.mozConnection || navigator.webkitConnection;
  var connInfo = conn ? (conn.effectiveType || '未知') + ' / 下行:' + (conn.downlink || '?') + 'Mbps' : '不支持';
  var dnt = navigator.doNotTrack === '1' ? '开启' : navigator.doNotTrack === '0' ? '关闭' : '未设置';
  var tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
  var docLang = document.documentElement.lang || '未知';
  var pdfViewer = navigator.pdfViewerEnabled !== undefined ? (navigator.pdfViewerEnabled ? '是' : '否') : '未知';
  var bi = document.getElementById('browserInfo');
  bi.innerHTML = '<div style="display:grid;gap:0.5rem;">' +
    '<div><b>User-Agent</b>:<br><code style="font-size:0.75rem;word-break:break-all;background:var(--bg-secondary);padding:4px 8px;border-radius:6px;display:block;margin-top:4px;">' + escHtml(ua) + '</code></div>' +
    '<div><b>语言</b>: ' + escHtml(langs) + '</div>' +
    '<div><b>平台</b>: ' + escHtml(plat) + '</div>' +
    '<div><b>CPU核心数</b>: ' + cores + '</div>' +
    '<div><b>设备内存</b>: ' + escHtml(mem) + '</div>' +
    '<div><b>GPU</b>: ' + escHtml(gpu) + '</div>' +
    '<div><b>网络类型</b>: ' + escHtml(connInfo) + '</div>' +
    '<div><b>时区</b>: ' + escHtml(tz) + '</div>' +
    '<div><b>文档语言</b>: ' + escHtml(docLang) + '</div>' +
    '<div><b>Cookie启用</b>: ' + (navigator.cookieEnabled ? '是' : '否') + '</div>' +
    '<div><b>PDF查看器</b>: ' + pdfViewer + '</div>' +
    '<div><b>DoNotTrack</b>: ' + escHtml(dnt) + '</div>' +
    '<div id="batRow"><b>电池</b>: <span style="color:var(--text-secondary);">检测中...</span></div>' +
    '</div>';
  if (navigator.getBattery) {
    navigator.getBattery().then(function(b) {
      var bch = b.charging ? '充电中' : '未充电';
      var lvl = Math.round(b.level * 100) + '%';
      var tStr = b.charging ? (b.chargingTime === Infinity ? '已充满' : '充满:' + Math.round(b.chargingTime/60) + 'min') : (b.dischargingTime === Infinity ? '计算中' : '剩余:' + Math.round(b.dischargingTime/3600) + 'h');
      var el = document.getElementById('batRow');
      if (el) el.innerHTML = '<b>电池</b>: ' + bch + ' ' + lvl + ' (' + tStr + ')';
    }).catch(function() {});
  }
  var sw = screen.width, sh = screen.height;
  var aw = window.innerWidth, ah = window.innerHeight;
  var dpr = window.devicePixelRatio || 1;
  var si = document.getElementById('screenInfo');
  si.innerHTML = '<div style="display:grid;gap:0.5rem;">' +
    '<div><b>屏幕分辨率</b>: ' + sw + ' x ' + sh + ' px</div>' +
    '<div><b>视口大小</b>: ' + aw + ' x ' + ah + ' px</div>' +
    '<div><b>物理像素宽度</b>: ' + Math.round(aw * dpr) + ' px</div>' +
    '<div><b>设备像素比</b>: ' + dpr + 'x</div>' +
    '<div><b>颜色深度</b>: ' + (screen.colorDepth || '未知') + ' bit</div>' +
    '<div><b>可用窗口</b>: ' + screen.availWidth + ' x ' + screen.availHeight + ' px</div>' +
    '<div><b>缩放比例</b>: ' + Math.round(dpr * 100) + '%</div>' +
    '</div>';
}
function escHtml(s) { return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
document.getElementById('refreshBtn').onclick = getBrowserInfo;
document.getElementById('copyBtn').onclick = function() {
  copyToClipboard('User-Agent: ' + navigator.userAgent + '\n语言: ' + (navigator.languages ? navigator.languages.join(',') : navigator.language) + '\n平台: ' + (navigator.platform||'未知') + '\n屏幕: ' + screen.width + 'x' + screen.height + '\n视口: ' + window.innerWidth + 'x' + window.innerHeight + '\n时区: ' + Intl.DateTimeFormat().resolvedOptions().timeZone);
  if (window.CT && CT.showToast) CT.showToast('已复制');
};
getBrowserInfo();

var canvas=document.getElementById('coordCanvas');
var ctx=canvas.getContext('2d');
var points=[];
var w,h;
function resize(){w=Math.min(800,canvas.offsetWidth||800);h=200;canvas.width=w;canvas.height=h;drawBg();}
function drawBg(){ctx.clearRect(0,0,w,h);ctx.fillStyle='#1a1a2e';ctx.fillRect(0,0,w,h);for(var x=0;x<w;x+=50){ctx.strokeStyle='rgba(255,255,255,0.05)';ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,h);ctx.stroke();}for(var y=0;y<h;y+=50){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(w,y);ctx.stroke();}points.forEach(function(p){ctx.beginPath();ctx.arc(p.x,p.y,4,0,Math.PI*2);ctx.fillStyle=p.c;ctx.fill();ctx.fillStyle='rgba(255,255,255,0.9)';ctx.font='10px monospace';ctx.fillText(p.x+','+p.y,p.x+8,p.y-5);});}
function updateCoords(e){var r=canvas.getBoundingClientRect();var ox=e.offsetX||(e.clientX-r.left);var oy=e.offsetY||(e.clientY-r.top);document.getElementById('clientCoord').textContent=e.clientX+', '+e.clientY;document.getElementById('pageCoord').textContent=e.pageX+', '+e.pageY;document.getElementById('screenCoord').textContent=e.screenX+', '+e.screenY;document.getElementById('offsetCoord').textContent=Math.round(ox)+', '+Math.round(oy);}
canvas.addEventListener('mousemove',updateCoords);
canvas.addEventListener('click',function(e){var r=canvas.getBoundingClientRect();var x=e.offsetX||(e.clientX-r.left);var y=e.offsetY||(e.clientY-r.top);var c='#'+(0x1000000*Math.random()|0).toString(16).slice(1);points.push({x:x,y:y,c:c});drawBg();var log=document.getElementById('coordLog');log.textContent=points.map(function(p){return'clientX='+p.x+', clientY='+p.y;}).join('\n');});
document.getElementById('clearBtn').onclick=function(){points=[];drawBg();document.getElementById('coordLog').textContent='';};
document.getElementById('copyCoords').onclick=function(){copyToClipboard(document.getElementById('coordLog').textContent);if(window.CT&&CT.showToast)CT.showToast('已复制');};
window.addEventListener('resize',resize);
resize();

var stops=[{color:'#667eea',pos:0},{color:'#764ba2',pos:100}];
var gType='linear',angle=90;
function buildG(){var parts=stops.map(function(s){return s.color+' '+s.pos+'%';}).join(', ');if(gType==='linear')return'linear-gradient('+angle+'deg, '+parts+')';if(gType==='radial')return'radial-gradient(circle, '+parts+')';if(gType==='conic')return'conic-gradient(from '+angle+'deg, '+parts+')';return parts;}
function update(){var g=buildG();document.getElementById('gradientPreview').style.background=g;document.getElementById('cssOutput').value='background: '+g+';\nbackground-image: '+g+';';}
function renderStops(){var el=document.getElementById('colorStops');el.innerHTML='';stops.forEach(function(stop,i){var row=document.createElement('div');row.style.cssText='display:flex;gap:0.5rem;align-items:center;';var c=document.createElement('input');c.type='color';c.value=stop.color;c.style.cssText='width:38px;height:30px;border:none;cursor:pointer;background:none;padding:0;';c.addEventListener('input',function(){stops[i].color=this.value;update();});var p=document.createElement('input');p.type='number';p.min=0;p.max=100;p.value=stop.pos;p.style.cssText='width:55px;padding:0.3rem;border:1px solid var(--border);border-radius:6px;font-size:0.82rem;';p.addEventListener('input',function(){stops[i].pos=parseInt(this.value)||0;update();});var lbl=document.createElement('span');lbl.textContent='%';var rm=document.createElement('button');rm.textContent='×';rm.style.cssText='width:24px;height:24px;border-radius:50%;border:none;background:#fee2e2;color:#ef4444;cursor:pointer;font-size:1rem;line-height:1;flex-shrink:0;';rm.addEventListener('click',function(){if(stops.length>2){stops.splice(i,1);renderStops();update();}});row.appendChild(c);row.appendChild(document.createTextNode(' '));row.appendChild(p);row.appendChild(lbl);row.appendChild(document.createTextNode(' '));row.appendChild(rm);el.appendChild(row);});}
document.getElementById('gradientType').addEventListener('change',function(e){gType=e.target.value;document.getElementById('angleRow').style.display=gType==='radial'?'none':'flex';update();});
document.getElementById('angleSlider').addEventListener('input',function(e){angle=parseInt(e.target.value);document.getElementById('angleInput').value=angle;update();});
document.getElementById('angleInput').addEventListener('input',function(e){angle=parseInt(e.target.value)||0;document.getElementById('angleSlider').value=angle;update();});
document.getElementById('addColorBtn').addEventListener('click',function(){var h=Math.floor(Math.random()*360);stops.push({color:'hsl('+h+',70%,60%)',pos:Math.floor(Math.random()*100)});renderStops();update();});
document.getElementById('genCssBtn').addEventListener('click',update);
document.getElementById('copyCss').addEventListener('click',function(){copyToClipboard(document.getElementById('cssOutput').value);if(window.CT&&CT.showToast)CT.showToast('已复制');});
renderStops();update();

