function beautify(){
var v=document.getElementById('input').value;
var beautified=v.replace(/\s*([{}:;,])\s*/g,'$1').replace(/;\s*}/g,';}').replace(/\{\s*/g,'{\n  ').replace(/\}\s*/g,'\n}\n').replace(/\n\s+/g,'\n  ').replace(/:\s+/g,': ');
document.getElementById('output').value=beautified.trim();
}
function compress(){
