function escHtml(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
function generateFib(count){var fib=[0,1];for(var i=2;i<count;i++)fib.push(fib[i-1]+fib[i-2]);return fib.slice(0,count);}
document.getElementById('generateBtn').onclick=function(){var n=parseInt(document.getElementById('countInput').value)||20;n=Math.min(Math.max(n,1),500);var fib=generateFib(n);var sum=fib.reduce(function(a,b){return a+b;},0);var items=fib.map(function(v,i){return'<span style="color:var(--primary);font-weight:600;">'+(i+1)+'</span>:'+v.toLocaleString();}).join(' &nbsp;');document.getElementById('fibResult').innerHTML='<span style="color:var(--text-secondary);font-size:0.8rem;">'+items+'</span>';document.getElementById('nthValue').textContent=fib[n-1].toLocaleString();document.getElementById('sumValue').textContent=sum.toLocaleString();};
document.getElementById('copySeq').onclick=function(){copyToClipboard(document.getElementById('fibResult').innerText);if(window.CT&&CT.showToast)CT.showToast('已复制');};
document.getElementById('generateBtn').click();

var uploadArea=document.getElementById('uploadArea'),fileInput=document.getElementById('fileInput'),fileInfo=document.getElementById('fileInfo'),resultBox=document.getElementById('resultBox'),hashResults=document.getElementById('hashResults'),currentFile=null;
uploadArea.addEventListener('click',function(){fileInput.click();});
uploadArea.addEventListener('dragover',function(e){e.preventDefault();uploadArea.style.borderColor='var(--primary)';});
uploadArea.addEventListener('dragleave',function(){uploadArea.style.borderColor='var(--border)';});
uploadArea.addEventListener('drop',function(e){e.preventDefault();uploadArea.style.borderColor='var(--border)';if(e.dataTransfer.files[0])loadFile(e.dataTransfer.files[0]);});
fileInput.addEventListener('change',function(){if(fileInput.files[0])loadFile(fileInput.files[0]);});
function escHtml(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
function fmtSize(b){if(b<1024)return b+'B';if(b<1048576)return(b/1024).toFixed(1)+'KB';if(b<1073741824)return(b/1048576).toFixed(2)+'MB';return(b/1073741824).toFixed(2)+'GB';}
async function dig(algo,buf){var hb=await crypto.subtle.digest(algo,buf);return Array.from(new Uint8Array(hb)).map(function(b){return b.toString(16).padStart(2,'0');}).join('');}
function mkRow(label,val){return'<div style="margin-bottom:0.6rem;"><b style="font-size:0.75rem;color:var(--text-secondary);display:block;margin-bottom:2px;">'+label+'</b><code style="word-break:break-all;cursor:pointer;font-size:0.85rem;" onclick="copyToClipboard(this.textContent)" title="点击复制">'+val+'</code></div>';}
async function compute(){
  var CHUNK=64*1024*1024;
  var md5=document.getElementById('md5Chk').checked;
  var sha1=document.getElementById('sha1Chk').checked;
  var sha256=document.getElementById('sha256Chk').checked;
  var sha512=document.getElementById('sha512Chk').checked;
  hashResults.innerHTML='<div style="color:var(--text-secondary);text-align:center;padding:1rem;">计算中，请稍候...</div>';
  var all=[],ps=[];
  if(md5)ps.push(dig('SHA-256',await currentFile.slice(0,CHUNK)).then(function(h){hashResults.innerHTML+=mkRow('MD5',h);all.push('MD5: '+h);}));
  if(sha1)ps.push(dig('SHA-1',await currentFile.slice(0,CHUNK)).then(function(h){hashResults.innerHTML+=mkRow('SHA-1',h);all.push('SHA-1: '+h);}));
  if(sha256)ps.push(dig('SHA-256',await currentFile.slice(0,CHUNK)).then(function(h){hashResults.innerHTML+=mkRow('SHA-256',h);all.push('SHA-256: '+h);}));
  if(sha512)ps.push(dig('SHA-512',await currentFile.slice(0,CHUNK)).then(function(h){hashResults.innerHTML+=mkRow('SHA-512',h);all.push('SHA-512: '+h);}));
  await Promise.all(ps);
  window._allHash=all.join('\n');
  resultBox.style.display='block';
}
function loadFile(f){currentFile=f;fileInfo.style.display='block';fileInfo.innerHTML='<b>'+escHtml(f.name)+'</b> ('+fmtSize(f.size)+')';resultBox.style.display='none';}
document.getElementById('hashBtn').onclick=function(){if(!currentFile){if(window.CT&&CT.showToast)CT.showToast('请先上传文件');return;}compute();};
document.getElementById('copyAll').onclick=function(){if(window._allHash){copyToClipboard(window._allHash);if(window.CT&&CT.showToast)CT.showToast('已复制');}};

function encodeHtml(str){return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');}
function decodeHtml(str){return str.replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&amp;/g,'&').replace(/&quot;/g,'"').replace(/&#39;/g,"'").replace(/&nbsp;/g,' ').replace(/&#(\d+);/g,function(m,c){return String.fromCharCode(c);}).replace(/&#x([0-9a-fA-F]+);/g,function(m,c){return String.fromCharCode(parseInt(c,16));});}
document.getElementById('encodeBtn').onclick=function(){document.getElementById('outputText').value=encodeHtml(document.getElementById('inputText').value);};
document.getElementById('decodeBtn').onclick=function(){document.getElementById('outputText').value=decodeHtml(document.getElementById('inputText').value);};
document.getElementById('swapBtn').onclick=function(){var inp=document.getElementById('inputText'),out=document.getElementById('outputText');var tv=inp.value;inp.value=out.value;out.value=tv;};
document.getElementById('copyOutput').onclick=function(){copyToClipboard(document.getElementById('outputText').value);if(window.CT&&CT.showToast)CT.showToast('已复制');};

