function beep(src){
var lines=src.split("\n");
var indent=0;
var out=[];
for(var i=0;i<lines.length;i++){
var raw=lines[i];
var line=raw.trim();
if(!line){out.push("");continue;}
if(line.indexOf("}")!==-1){indent=Math.max(0,indent-1);}
out.push(sp(indent)+line);
if(line.indexOf("{")!==-1||line.indexOf(";")===line.length-1){indent++;}
}
return out.join("\n");
}
function sp(n){var r="";for(var i=0;i<n*2;i++)r+=" ";return r;}
window.beautify=function(){
try{
var v=document.getElementById("input").value;
document.getElementById("output").value=beep(v);
document.getElementById("errorMsg").style.display="none";
}catch(e){
document.getElementById("errorMsg").textContent=e.message;
document.getElementById("errorMsg").style.display="block";
}
};
window.minify=function(){
var v=document.getElementById("input").value;
document.getElementById("output").value=v.replace(/\s+/g," ").replace(/\s*([\{\}\(\)\;,])\s*/g,"$1").trim();
document.getElementById("errorMsg").style.display="none";
};
window.copyOutput=function(){navigator.clipboard.writeText(document.getElementById("output").value);};
})();

(function() {
  // Init shared UI
  if (typeof CT === 'undefined') {
    var nav = document.querySelector('.navbar');
    var footer = document.querySelector('.footer');
    if (nav) nav.innerHTML = '<div class="nav-inner"><a href="/" class="nav-brand">🍀 CloverTools</a><nav class="site-nav"><a href="/" class="nav-icon-link"><span>工具</span></a><a href="/blog/" class="nav-icon-link"><span>问题</span></a></nav></div>';
    if (footer) footer.innerHTML = '<div class="footer-inner">© 2026 <a href="/">CloverTools</a></div>';
  }

  function escapeHtml(str) {
    return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  function formatVal(v) {
    if (v === null) return '<span class="diff-val-null">null</span>';
    if (typeof v === 'boolean') return '<span class="diff-val-bool">' + v + '</span>';
    if (typeof v === 'number') return '<span class="diff-val-num">' + v + '</span>';
    return '<span class="diff-val-str">"' + escapeHtml(String(v)) + '"</span>';
  }

  var countAdd = 0, countDel = 0, countChg = 0, countSame = 0;

  function diffObjects(left, right, path) {
    var lines = [];
    var keys = new Set();
    Object.keys(left || {}).forEach(function(k) { keys.add(k); });
    Object.keys(right || {}).forEach(function(k) { keys.add(k); });
    var sortedKeys = Array.from(keys).sort();

    sortedKeys.forEach(function(key) {
      var p = path ? path + '.' + key : key;
      var lh = left && left.hasOwnProperty(key);
      var rh = right && right.hasOwnProperty(key);
      var lv = lh ? left[key] : undefined;
      var rv = rh ? right[key] : undefined;
      var bothObj = (lv !== undefined && typeof lv === 'object' && lv !== null) &&
                     (rv !== undefined && typeof rv === 'object' && rv !== null) &&
                     !Array.isArray(lv) && !Array.isArray(rv);

      if (!lh && rh) {
        countAdd++;
        lines.push('<div class="diff-line diff-add"><span class="diff-key">"' + escapeHtml(key) + '"</span>: ' + formatVal(rv) + ' <span style="opacity:0.6;font-size:0.75em;">← 新增</span></div>');
      } else if (lh && !rh) {
        countDel++;
        lines.push('<div class="diff-line diff-del"><span class="diff-key">"' + escapeHtml(key) + '"</span>: ' + formatVal(lv) + ' <span style="opacity:0.6;font-size:0.75em;">← 已删除</span></div>');
      } else if (bothObj) {
        var sub = diffObjects(lv, rv, p);
        if (sub) lines.push('<div class="diff-line diff-unchanged"><span class="diff-key">"' + escapeHtml(key) + '":</span> {</div>' + sub + '<div class="diff-line diff-unchanged">}</div>');
        else { countSame++; }
      } else if (JSON.stringify(lv) !== JSON.stringify(rv)) {
        countChg++;
        lines.push('<div class="diff-line diff-chg"><span class="diff-key">"' + escapeHtml(key) + '"</span>: ' + formatVal(lv) + ' → ' + formatVal(rv) + '</div>');
      } else {
        countSame++;
        lines.push('<div class="diff-line diff-unchanged"><span class="diff-key">"' + escapeHtml(key) + '"</span>: ' + formatVal(lv) + '</div>');
      }
    });
    return lines.join('');
  }

  window.doDiff = function() {
    var err = document.getElementById('errorBox');
    var summary = document.getElementById('summaryBar');
    var output = document.getElementById('diffOutput');
    err.style.display = 'none';
    summary.style.display = 'none';
    countAdd = countDel = countChg = countSame = 0;

    var leftVal = document.getElementById('leftJson').value.trim();
    var rightVal = document.getElementById('rightJson').value.trim();

    if (!leftVal && !rightVal) {
      output.innerHTML = '<div class="empty-state">输入两侧 JSON 后点击「对比 JSON」查看差异…</div>';
      return;
    }

    var leftObj, rightObj;
    try { leftObj = leftVal ? JSON.parse(leftVal) : {}; } catch(e) {
      err.textContent = '⚠ 左侧 JSON 解析失败：' + e.message;
      err.style.display = 'block'; return;
    }
    try { rightObj = rightVal ? JSON.parse(rightVal) : {}; } catch(e) {
      err.textContent = '⚠ 右侧 JSON 解析失败：' + e.message;
      err.style.display = 'block'; return;
    }

    var result = diffObjects(leftObj, rightObj, '');
    if (!result) {
      output.innerHTML = '<div class="empty-state">✅ 两侧 JSON 完全相同，无差异</div>';
    } else {
      output.innerHTML = result;
    }

    document.getElementById('countAdd').textContent = countAdd;
    document.getElementById('countDel').textContent = countDel;
    document.getElementById('countChg').textContent = countChg;
    document.getElementById('countSame').textContent = countSame;
    summary.style.display = 'flex';
  };

  window.swapAndDiff = function() {
    var l = document.getElementById('leftJson');
    var r = document.getElementById('rightJson');
    var tmp = l.value; l.value = r.value; r.value = tmp;
    doDiff();
  };

  window.clearAll = function() {
    document.getElementById('leftJson').value = '';
    document.getElementById('rightJson').value = '';
