function renderMd(md){
  md=md.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  md=md.replace(/^######\s+(.+)$/gm,'<h6>$1</h6>');
  md=md.replace(/^#####\s+(.+)$/gm,'<h5>$1</h5>');
  md=md.replace(/^####\s+(.+)$/gm,'<h4>$1</h4>');
  md=md.replace(/^###\s+(.+)$/gm,'<h3>$1</h3>');
  md=md.replace(/^##\s+(.+)$/gm,'<h2>$1</h2>');
  md=md.replace(/^#\s+(.+)$/gm,'<h1>$1</h1>');
  md=md.replace(/\*\*(.+?)\*\*/g,'<b>$1</b>');
  md=md.replace(/\*(.+?)\*/g,'<i>$1</i>');
  md=md.replace(/`([^`]+)`/g,function(m,code){return '<code style="background:rgba(0,0,0,.06);padding:.1rem .3rem;border-radius:3px;font-family:monospace">'+escHtml(code)+'</code>';});
  md=md.replace(/```([\s\S]*?)```/g,'<pre style="background:var(--result-bg);padding:1rem;border-radius:8px;overflow-x:auto"><code>$1</code></pre>');
  md=md.replace(/^\*\s+(.+)$/gm,'<li>$1</li>');
  md=md.replace(/^\d+\.\s+(.+)$/gm,'<li>$1</li>');
  md=md.replace(/\n\n/g,'</p><p style="margin:1rem 0">');
  md='<p style="margin:.5rem 0">'+md+'</p>';
  md=md.replace(/<p style="margin:.5rem 0"><(h[1-6]|pre|ul|ol|li)/g,'<$1');
