var U="ABCDEFGHIJKLMNOPQRSTUVWXYZ";
var L="abcdefghijklmnopqrstuvwxyz";
var N="0123456789";
var S="!@#$%^&*()_+-=[]{}|;:,.<>?";
function genPwd(len,upper,lower,num,sym){
var chars="";
if(upper)chars+=U;if(lower)chars+=L;if(num)chars+=N;if(sym)chars+=S;
if(!chars)chars=L+N;
var gpwd="";var arr=new Uint32Array(len);
crypto.getRandomValues(arr);
for(var i=0;i<len;i++)gpwd+=chars[arr[i]%chars.length];
return gpwd;
}
function strength(gpwd){
var score=0;
if(gpwd.length>=8)score++;if(gpwd.length>=12)score++;if(gpwd.length>=16)score++;
if(/[A-Z]/.test(gpwd)&&/[a-z]/.test(gpwd))score++;
if(/[0-9]/.test(gpwd))score++;if(/[^A-Za-z0-9]/.test(gpwd))score++;
if(score<=2)return{label:"\u5f31",cls:"strength-weak"};
if(score<=4)return{label:"\u4e2d\u7b49",cls:"strength-fair"};
if(score<=5)return{label:"\u826f\u597d",cls:"strength-good"};
