weight:{'克(g)':1,'千克(kg)':1000,'毫克(mg)':0.001,'吨(t)':1000000,'磅(lb)':453.592,'盎司(oz)':28.3495,'斤':500,'两':50,'钱':5},
area:{'平方米(m2)':1,'平方千米(km2)':1e6,'公顷(ha)':10000,'亩':666.667,'分':66.667,'平方英尺(sqft)':0.092903,'平方英里(sqmi)':2589988,'英亩(acre)':4046.86},
speed:{'米/秒(m/s)':1,'千米/时(km/h)':0.277778,'英里/时(mph)':0.44704,'节(knot)':0.514444,'英尺/秒(ft/s)':0.3048,'马赫(Mach)':340.29},
time:{'秒(s)':1,'毫秒(ms)':0.001,'微秒(us)':0.000001,'分钟(min)':60,'小时(h)':3600,'天(d)':86400,'周(week)':604800,'月(month)':2629746,'年(year)':31556952},
power:{'瓦(W)':1,'千瓦(kW)':1000,'马力(HP)':745.7,'英制马力(bhp)':745.7}
};
var curCat='length';
window.setCategory=function(cat){
curCat=cat;
document.querySelectorAll('.unit-tab').forEach(function(b){b.className='unit-tab btn btn-secondary';});
document.getElementById('tab-'+cat).className='unit-tab btn btn-primary';
var sel1=document.getElementById('fromUnit');
var sel2=document.getElementById('toUnit');
sel1.innerHTML='';sel2.innerHTML='';
cats[cat].units.forEach(function(u,i){sel1.innerHTML+='<option value="'+u+'"'+(i===0?' selected':'')+'>'+u+'</option>';sel2.innerHTML+='<option value="'+u+'"'+(i===1?' selected':'')+'>'+u+'</option>';});
document.getElementById('fromVal').value='';
document.getElementById('result').textContent='0';
document.getElementById('resultDetail').innerHTML='';
};
window.convert=function(){
var v=parseFloat(document.getElementById('fromVal').value);
if(isNaN(v)){document.getElementById('result').textContent='0';document.getElementById('resultDetail').innerHTML='';return;}
var fu=document.getElementById('fromUnit').value;
var tu=document.getElementById('toUnit').value;
var result;
if(curCat==='temp'){
if(fu==='摄氏度(C)'&&tu==='华氏度(F)')result=v*9/5+32;
else if(fu==='华氏度(F)'&&tu==='摄氏度(C)')result=(v-32)*5/9;
else if(fu==='摄氏度(C)'&&tu==='开尔文(K)')result=v+273.15;
else if(fu==='开尔文(K)'&&tu==='摄氏度(C)')result=v-273.15;
else if(fu==='华氏度(F)'&&tu==='开尔文(K)')result=(v-32)*5/9+273.15;
else if(fu==='开尔文(K)'&&tu==='华氏度(F)')result=(v-273.15)*9/5+32;
else result=v;
}else{
var f=convFactors[curCat][fu];
var t=convFactors[curCat][tu];
result=(v*f)/t;
}
var decimals=Math.abs(result)>1000?2:Math.abs(result)<0.001?6:4;
document.getElementById('result').textContent=result.toFixed(decimals)+' '+tu;
var detail='<b>'+v.toLocaleString()+'</b> '+fu+' = <b>'+result.toLocaleString(undefined,{minimumFractionDigits:decimals,maximumFractionDigits:decimals})+'</b> '+tu;
document.getElementById('resultDetail').innerHTML=detail;
};
window.swapUnits=function(){
var fu=document.getElementById('fromUnit');
var tu=document.getElementById('toUnit');
var tmp=fu.value;fu.value=tu.value;tu.value=tmp;
convert();
};
setCategory('length');
})();

