    if (footer) footer.innerHTML = '<div class="footer-inner">© 2026 <a href="/">CloverTools</a></div>';
  }

  function rand12() { return Math.floor(Math.random() * 0x10000000000); }
  function rand16() { return Math.floor(Math.random() * 0x1000000000000); }

  function uuid7(epochMs) {
    var t = epochMs || Date.now();
    var tb = t.toString(16).padStart(12, '0');
    var tl = parseInt(tb.slice(0,8), 16);
    var th = parseInt(tb.slice(8), 16);
    // version 7 (4 bits) + 12 bits rand in the 48-bit timestamp
    var ver_and_rand1 = (0x7000 | (Math.floor(Math.random() * 0x1000)));
    var rand2 = rand12();
    var rand3 = rand16();
    // variant 10 (10xx)
    var variant = 0x8000 | (Math.floor(Math.random() * 0x4000));
    var a = ((tl & 0x0000ffff) | ((th & 0x00ff) << 16)).toString(16).padStart(4,'0');
    var b = ((tl >> 16) & 0xffff).toString(16).padStart(4,'0');
    var c = (ver_and_rand1 | ((th >> 8) & 0x0fff)).toString(16).padStart(4,'0');
    var d = variant.toString(16).padStart(4,'0');
    var e = rand2.toString(16).padStart(10,'0');
    var f = rand3.toString(16).padStart(12,'0');
    return a + '-' + b + '-' + c + '-' + d + '-' + e + f;
  }

  function fmtUuid(uuid, format) {
    if (format === 'compact') return uuid.replace(/-/g, '');
    if (format === 'upper') return uuid.toUpperCase();
    return uuid;
  }

  window.genSingle = function() {
    var fmt = document.getElementById('format').value;
    var u = fmtUuid(uuid7(), fmt);
    document.getElementById('singleOutput').textContent = u;
    document.getElementById('singleOutput').style.cursor = 'pointer';
    document.getElementById('singleOutput').onclick = function() { navigator.clipboard.writeText(u); this.textContent = '✅ 已复制！'; setTimeout(function(){ document.getElementById('singleOutput').textContent = u; }, 1200); };
  };

  window.genBatch = function() {
    var count = parseInt(document.getElementById('batchCount').value) || 10;
    count = Math.min(Math.max(count, 1), 1000);
    var fmt = document.getElementById('format').value;
    var list = document.getElementById('uuidList');
    var card = document.getElementById('batchCard');
    list.innerHTML = '';
    document.getElementById('batchCount2').textContent = count + ' 个';
    for (var i = 0; i < count; i++) {
      var u = fmtUuid(uuid7(), fmt);
      var ms = Date.now();
      var d = new Date(ms);
      var timeStr = d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0')+' '+String(d.getHours()).padStart(2,'0')+':'+String(d.getMinutes()).padStart(2,'0')+':'+String(d.getSeconds()).padStart(2,'0');
      var item = document.createElement('div');
      item.className = 'uuid-item';
      item.innerHTML = '<span><span class="uuid-num">' + (i+1) + '</span><span class="uuid-val">' + u + '</span><span class="uuid-time">' + timeStr + '</span></span><span class="copy-icon" onclick="copyUuid(this,\'' + u.replace(/'/g,"\\'") + '\')">📋</span>';
      list.appendChild(item);
    }
    card.style.display = 'block';
  };

  window.genFromTimestamp = function() {
    var tsInput = document.getElementById('unixMs').value.trim();
    var dtInput = document.getElementById('customTime').value;
    var ms;
    if (tsInput) {
      ms = parseInt(tsInput);
      if (isNaN(ms)) { alert('时间戳格式错误'); return; }
    } else if (dtInput) {
      ms = new Date(dtInput).getTime();
    } else {
      document.getElementById('timestampInfo').textContent = '请输入时间戳或选择日期时间';
      return;
    }
    var fmt = document.getElementById('format').value;
    var u = fmtUuid(uuid7(ms), fmt);
    document.getElementById('singleOutput').textContent = u;
    document.getElementById('timestampInfo').textContent = '时间：' + new Date(ms).toLocaleString('zh-CN', {timeZone:'Asia/Shanghai'}) + '  →  毫秒：' + ms;
  };

  window.clearAll = function() {
    document.getElementById('singleOutput').textContent = '点击按钮生成 UUID v7…';
    document.getElementById('singleOutput').onclick = null;
    document.getElementById('uuidList').innerHTML = '';
    document.getElementById('batchCard').style.display = 'none';
  };

  window.copyUuid = function(el, uuid) {
    navigator.clipboard.writeText(uuid);
    el.textContent = '✅';
    setTimeout(function() { el.textContent = '📋'; }, 1000);
  };

  window.copyAll = function() {
    var uuids = Array.from(document.querySelectorAll('.uuid-val')).map(function(el) { return el.textContent; }).join('\n');
    navigator.clipboard.writeText(uuids);
  };

  // Init timestamp field with current time
  var now = new Date();
  now.setMilliseconds(0);
  document.getElementById('customTime').value = now.toISOString().slice(0,16);
})();

