// ── Call API ────────────────────────────────
function callAI(task,payload,callback){
  var modelId=document.getElementById("modelSelect").value;
  var apiKey=document.getElementById("apiKeyInput").value.trim();
  var baseUrlInput=document.getElementById("baseUrlInput").value.trim();

  if(!apiKey){callback({error:"请先输入并保存 API Key"});return;}

  var cfg=MODEL_CONFIGS[modelId];
  var baseUrl=baseUrlInput||cfg.baseUrl;
  if(!baseUrl){callback({error:"请填写 API Base URL"});return;}

  var endpoint=cfg.endpoint;
  var url=baseUrl.replace(/\/$/,"")+endpoint;
  var headers=cfg.headers(apiKey);
  var body=cfg.buildBody(buildMsgs(task,payload));

  // For custom model, use whatever model user sets
  if(modelId==="custom"){
    var customModel=document.getElementById("baseUrlInput").value.trim();
    // model from custom is set in buildBody already
  }

  // Anthropic needs a different body structure
  if(modelId==="anthropic"){
    body={model:cfg.model,max_tokens:2000,messages:[body.messages[1]]};
  }

  fetch(url,{
    method:"POST",
    headers:headers,
    body:JSON.stringify(body)
  }).then(function(res){
    return res.json().then(function(data){
      if(!res.ok){
        callback({error:(data.error&&data.error.message)||"API 请求失败 ("+res.status+")"});
      } else {
        try{
          var text=cfg.parse(data);
          callback({text:text});
        }catch(e){
          callback({error:"解析响应失败："+e.message});
        }
      }
    });
  }).catch(function(err){
    callback({error:"网络错误："+err.message});
  });
}

