function detect(){
var text=document.getElementById('inputText').value.trim();
var resultSection=document.getElementById('resultSection');
if(text.length<20){
resultSection.style.display='none';
return;
}
resultSection.style.display='block';
// Calculate features
var sents=text.split(/[。！？.!?]+/).filter(function(s){return s.trim().length>0;});
var words=text.split(/\s+/).filter(function(w){return w.length>0;});
var uniqueWords={};
words.forEach(function(w){var l=w.toLowerCase().replace(/[^a-z\u4e00-\u9fa5]/g,'');if(l)uniqueWords[l]=1;});
var uwr=Object.keys(uniqueWords).length/Math.max(words.length,1);
// Sentence length variation
var avgLen=sents.length>0?sents.reduce(function(a,s){return a+s.length;},0)/sents.length:0;
var varLen=sents.length>1?sents.reduce(function(a,s){return a+Math.pow(s.length-avgLen,2);},0)/sents.length:0;
var cv=avgLen>0?Math.sqrt(varLen)/avgLen:0;
// Punctuation density
var punctCount=(text.match(/[，。、；：""''【】（)（）《》]/g)||[]).length;
var punctRatio=punctCount/Math.max(text.length,1);
// Chinese char ratio
var chineseChars=(text.match(/[\u4e00-\u9fa5]/g)||[]).length;
var charRatio=chineseChars/Math.max(text.length,1);
// AI patterns: low lexical diversity, uniform sentence length, high punct ratio, formal words
var formalWords=['因此','然而','此外','与此同时','综上所述','显而易见','毫无疑问','值得注意的是','换言之','一言以蔽之'];
var formalCount=0;
formalWords.forEach(function(w){if(text.indexOf(w)>-1)formalCount++;});
var formalRatio=formalCount/Math.max(formalWords.length,1);
// Repetition detection
var bigrams={};
for(var i=0;i<text.length-1;i++){
var bg=text.substring(i,i+2);
bigrams[bg]=(bigrams[bg]||0)+1;
}
var maxBigramFreq=Math.max.apply(null,Object.values(bigrams)||[0]);
var bigramRatio=maxBigramFreq/Math.max(text.length-1,1);
// AI SCORE (0=definitely human, 100=definitely AI)
var aiScore=0;
if(text.length<100)aiScore+=20;
if(uwr<0.4)aiScore+=20;
if(cv<0.25)aiScore+=15;
if(punctRatio>0.08)aiScore+=10;
if(formalCount>=3)aiScore+=15;
if(bigramRatio>0.015)aiScore+=10;
aiScore=Math.max(0,Math.min(100,aiScore));
// Display
var pct=document.getElementById('aiPct');
var label=document.getElementById('resultLabel');
var circle=document.getElementById('resultCircle');
var bar=document.getElementById('scoreBar');
pct.textContent=Math.round(aiScore)+'%';
if(aiScore>=70){
label.textContent='高概率AI生成';
circle.className='result-circle score-high';
bar.style.background='linear-gradient(90deg,#ff6b6b,#ee5a5a)';
}else if(aiScore>=40){
label.textContent='可能是AI辅助';
circle.className='result-circle score-medium';
bar.style.background='linear-gradient(90deg,#ffd93d,#f5c400)';
}else{
label.textContent='高概率真人写作';
circle.className='result-circle score-low';
bar.style.background='linear-gradient(90deg,#51cf66,#40c057)';
}
bar.style.width=aiScore+'%';
// Indicators
var indHTML='';
var inds=[
{val:(uwr*100).toFixed(0)+'%',lab:'词汇丰富度',bad:uwr<0.4},
{val:cv.toFixed(2),lab:'句长变异系数',bad:cv<0.25},
{val:(punctRatio*100).toFixed(1)+'%',lab:'标点密度',bad:punctRatio>0.08},
{val:(charRatio*100).toFixed(0)+'%',lab:'中文字符比',bad:charRatio>0.85},
{val:formalCount+'个',lab:'书面语词数',bad:formalCount>=3},
];
inds.forEach(function(ind){
indHTML+='<div class="indicator"><div class="val" style="color:'+(ind.bad?'var(--primary)':'#51cf66')+'">'+ind.val+'</div><div class="lab">'+ind.lab+'</div></div>';
});
document.getElementById('indicators').innerHTML=indHTML;
}
window.detect=detect;
})();

