function lcs(a,b){
var m=a.length,n=b.length;
var dp=Array(m+1).fill(null).map(function(){return Array(n+1).fill(0);});
for(var i=1;i<=m;i++){for(var j=1;j<=n;j++){if(a[i-1]===b[j-1])dp[i][j]=dp[i-1][j-1]+1;else dp[i][j]=Math.max(dp[i-1][j],dp[i][j-1]);}}
var lcsArr=[];
var i=m,j=n;
while(i>0&&j>0){if(a[i-1]===b[j-1]){lcsArr.unshift(a[i-1]);i--;j--;}else if(dp[i-1][j]>dp[i][j-1])i--;else j--;}
return lcsArr.join("");
}
