function fixText(input){
try{
var buf=new ArrayBuffer(input.length*2);
var bufView=new Uint16Array(buf);
for(var i=0;i<input.length;i++)bufView[i]=input.charCodeAt(i);
var bytes=new Uint8Array(buf);
var encs=["UTF-8","GBK","GB18030","BIG5","LATIN1"];
var fixes=[];
encs.forEach(function(enc){
try{
var decoded=new TextDecoder(enc,{fatal:false}).decode(bytes);
if(decoded&&decoded.indexOf("�")===-1&&decoded.trim().length>input.length*0.3){
fixes.push({enc:enc,text:decoded});
}
}catch(e){}
});
if(fixes.length>0){
var best=fixes.reduce(function(a,b){return a.text.length>b.text.length?a:b;});
return {ok:true,text:best.text,enc:best.enc};
}else{
return {ok:false,text:input,enc:"未知"};
}
}catch(e){return {ok:false,text:input,enc:"错误"};}
}
