function dedupe(){
var t=document.getElementById('input').value;
var lines=t.split('\n');
var keepOrder=document.getElementById('keepOrder').checked;
var seen={};
var unique=[];
var removed=0;
lines.forEach(function(line){
if(line.trim()===''){unique.push(line);return;}
var key=line;
if(seen[key]){removed++;}else{seen[key]=true;unique.push(line);}
});
var filtered=unique.filter(function(l){return l.trim()!=='';});
var result=keepOrder?filtered.join('\n'):filtered.sort().join('\n');
document.getElementById('output').value=result;
var outLines=result.split('\n').filter(function(l){return l.length>0;});
document.getElementById('statsInfo').textContent='原始 '+lines.length+' 行，去重后 '+outLines.length+' 行，删除了 '+removed+' 个重复项';
}
