function hexToRgb(hex){
var m=hex.match(/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i);
return m?[parseInt(m[1],16),parseInt(m[2],16),parseInt(m[3],16)]:null;
}
function rgbToHex(r,g,b){return'#'+[r,g,b].map(function(x){return x.toString(16).padStart(2,'0');}).join('');}
function rgbToHsl(r,g,b){
r/=255;g/=255;b/=255;
var max=Math.max(r,g,b),min=Math.min(r,g,b);
var h,s,l=(max+min)/2;
if(max===min){h=s=0;}
else{var d=max-min;s=l>.5?d/(2-max-min):d/(max+min);switch(max){case r:h=(g-b)/d+(g<b?6:0);break;case g:h=(b-r)/d+2;break;case b:h=(r-g)/d+4;}h/=6;}
return[h*360,s,l];
}
function showColor(hex){
var rgb=hexToRgb(hex)||[];
var r=rgb[0],g=rgb[1],b=rgb[2];
var hsl=rgbToHsl(r,g,b);
var html='<div style="background:var(--result-bg);border-radius:8px;padding:.75rem"><div style="font-weight:600;margin-bottom:.3rem">HEX</div><div>'+hex+'</div></div>';
html+='<div style="background:var(--result-bg);border-radius:8px;padding:.75rem"><div style="font-weight:600;margin-bottom:.3rem">RGB</div><div>rgb('+r+', '+g+', '+b+')</div></div>';
html+='<div style="background:var(--result-bg);border-radius:8px;padding:.75rem"><div style="font-weight:600;margin-bottom:.3rem">RGBA</div><div>rgba('+r+', '+g+', '+b+', 1)</div></div>';
html+='<div style="background:var(--result-bg);border-radius:8px;padding:.75rem"><div style="font-weight:600;margin-bottom:.3rem">HSL</div><div>hsl('+Math.round(hsl[0])+', '+Math.round(hsl[1]*100)+'%, '+Math.round(hsl[2]*100)+'%)</div></div>';
document.getElementById('colorResults').innerHTML=html;
document.getElementById('colorPreview').style.background=hex;
}
window.update=function(){
