tools.convertFn:
function convert(value, direction) {
  if (direction === 'dec2hex') {
    var n = parseInt(value, 10);
    if (isNaN(n)) return '错误：无效的十进制数字';
    return n.toString(16).toUpperCase();
  }
  if (direction === 'hex2dec') {
    var n = parseInt(value, 16);
    if (isNaN(n)) return '错误：无效的十六进制数字';
    return String(n);
  }
  if (direction === 'dec2bin') {
    var n = parseInt(value, 10);
    if (isNaN(n)) return '错误：无效的十进制数字';
    return n.toString(2);
  }
  if (direction === 'bin2dec') {
    var n = parseInt(value, 2);
    if (isNaN(n)) return '错误：无效的二进制数字';
    return String(n);
  }
  if (direction === 'dec2oct') {
    var n = parseInt(value, 10);
    if (isNaN(n)) return '错误：无效的十进制数字';
    return n.toString(8);
  }
  if (direction === 'oct2dec') {
    var n = parseInt(value, 8);
    if (isNaN(n)) return '错误：无效的八进制数字';
    return String(n);
  }
  if (direction === 'hex2bin') {
    return parseInt(value, 16).toString(2);
  }
  if (direction === 'bin2hex') {
    return parseInt(value, 2).toString(16).toUpperCase();
  }
  return value;
}

tools.customScript:
var methodSel=document.getElementById('method');
    var urlInput=document.getElementById('urlInput');
    var headersInput=document.getElementById('headersInput');
    var bodyInput=document.getElementById('bodyInput');
    var sendBtn=document.getElementById('sendBtn');
    var resArea=document.getElementById('resArea');
    var loading=document.getElementById('loading');
    var statusCode=document.getElementById('statusCode');
    var resTime=document.getElementById('resTime');
    var resBody=document.getElementById('resBody');

    methodSel.addEventListener('change',function(){
      var m=methodSel.value;
      document.getElementById('bodySection').style.display=(m==='GET'||m==='DELETE')?'none':'block';
    });

    function parseHeaders(hdrStr){
      var headers={};
      if(!hdrStr)return headers;
      hdrStr.split('\n').forEach(function(line){
        var idx=line.indexOf(':');
        if(idx>0){
          var key=line.substring(0,idx).trim();
          var val=line.substring(idx+1).trim();
          headers[key]=val;
        }
      });
      return headers;
    }

    function fmtTime(ms){
      if(ms<1000)return ms+'ms';
      return(ms/1000).toFixed(2)+'s';
    }

    function fmtJson(str){
      try{
        var obj=JSON.parse(str);
        return JSON.stringify(obj,null,2);
      }catch(e){
        return str;
      }
    }

    function getStatusClass(code){
      if(code>=200&&code<300)return'status-ok';
      if(code>=300&&code<400)return'status-redirect';
      return'status-error';
    }

    function sendReq(){
      var url=urlInput.value.trim();
      if(!url){if(window.CT&&CT.showToast)CT.showToast('\u8bf7\u8f93\u5165URL');return;}
      var method=methodSel.value;
      var headers=parseHeaders(headersInput.value);
      var body=method!=='GET'&&method!=='DELETE'?bodyInput.value:null;
      if(!headers['Content-Type']&&body)headers['Content-Type']='application/json';
      sendBtn.disabled=true;
      resArea.style.display='none';
      loading.style.display='block';
      var startTime=Date.now();
      var options={method:method,headers:headers};
      if(body)options.body=body;
      var controller=new AbortController();
      options.signal=controller.signal;
      setTimeout(function(){controller.abort();},30000);
      fetch(url,options).then(function(resp){
        var elapsed=Date.now()-startTime;
        statusCode.textContent=resp.status+' '+resp.statusText;
        statusCode.className='status-code '+getStatusClass(resp.status);
        resTime.textContent=fmtTime(elapsed);
        return resp.text();
      }).then(function(text){
        loading.style.display='none';
        resArea.style.display='block';
        resBody.textContent=fmtJson(text);
        sendBtn.disabled=false;
      }).catch(function(err){
        loading.style.display='none';
        resArea.style.display='block';
        statusCode.textContent='Error';
        statusCode.className='status-code status-error';
        resTime.textContent='';
        resBody.textContent='\u8bf7\u6c42\u5931\u8d25: '+err.message+'\n\n\u6ce8\u610f: \u6d4b\u8bd5\u8b66\u6d3d\u7684API\u53ef\u80fd\u56e0\u4e3aCORS\u9519\u8bef\u88ab\u9632\u6b62\u8bbf\u95ee';
        sendBtn.disabled=false;
      });
    }
    urlInput.addEventListener('keydown',function(e){if(e.key==='Enter')sendReq();});
  </script>

(function() {
  // Navigation/footer shared.js doesn't autoinit for custom tools, init manually
  if (typeof CT === 'undefined') {
    document.querySelector('.navbar').innerHTML = '<div class="nav-inner"><a href="/" class="nav-brand">🍀 CloverTools</a><div class="nav-links"><a href="/" class="nav-link">首页</a></div></div>';
    document.querySelector('.footer').innerHTML = '<div class="footer-inner">© 2026 <a href="/">CloverTools</a> · <a href="/changelog.html">更新日志</a></div>';
  }

  function parseField(val, min, max) {
    if (val === '*') return { type: 'all', values: [] };
    if (val.startsWith('*/')) {
      var step = parseInt(val.slice(2));
      if (isNaN(step) || step <= 0) return null;
      var vals = [];
      for (var i = min; i <= max; i += step) vals.push(i);
      return { type: 'step', step: step, values: vals };
    }
    if (val.includes(',')) {
      var parts = val.split(',');
      var allOk = parts.every(function(p) { return !isNaN(parseInt(p)) && parseInt(p) >= min && parseInt(p) <= max; });
      if (!allOk) return null;
      return { type: 'list', values: parts.map(function(p) { return parseInt(p); }) };
    }
    var num = parseInt(val);
    if (isNaN(num) || num < min || num > max) return null;
    return { type: 'single', values: [num] };
  }

  function describeField(val, min, max, unit) {
    if (val === '*') return '每' + unit;
    if (val.startsWith('*/')) return '每' + val.slice(2) + '个' + unit;
    if (val.includes(',')) {
      var parts = val.split(',');
      if (parts.length <= 3) return parts.map(function(p) { return '第' + p + unit; }).join('、') + '执行';
      return parts.length + '个指定' + unit;
    }
    return '第' + val + unit;
  }

  function describeCron(min, hr, day, mon, wd) {
    var parts = [];
    var brief = '';
    brief += describeField(min, 0, 59, '分钟').replace('每', '');
    brief += '、' + describeField(hr, 0, 23, '点').replace('第', '');
    if (day !== '*' || wd !== '*') {
      if (day !== '*' && wd === '*') brief += '、每月第' + day + '天';
      if (wd !== '*' && day === '*') {
        var wdNames = ['周日','周一','周二','周三','周四','周五','周六'];
        if (wd.includes(',')) {
          brief += '、每' + wd.split(',').map(function(d) { return wdNames[parseInt(d)]; }).join('和');
        } else {
          brief += '、每' + wdNames[parseInt(wd)];
        }
      }
    }
    if (mon !== '*') brief += '、' + describeField(mon, 1, 12, '月').replace('第', '');
    return brief;
  }

  function getNextRuns(min, hr, day, mon, wd, count) {
    var runs = [];
    var now = new Date();
    var d = new Date(now);
    d.setSeconds(0);
    d.setMilliseconds(0);
    d.setMinutes(d.getMinutes() + 1);

    var minuteOk = function(m) { return min === '*' || min.startsWith('*/') ? (m % parseInt(min.slice(2)) === 0) : min.split(',').map(Number).includes(m); };
    var hourOk = function(h) { return hr === '*' || hr.startsWith('*/') ? (h % parseInt(hr.slice(2)) === 0) : hr.split(',').map(Number).includes(h); };
    var dayOk = function(d_) { return day === '*' || day.split(',').map(Number).includes(d_); };
    var monOk = function(m_) { return mon === '*' || mon.split(',').map(Number).includes(m_); };
    var wdOk = function(w) { return wd === '*' || wd.split(',').map(Number).includes(w); };

    var checked = 0;
    var maxIter = 525600; // 1 year in minutes
    for (var i = 0; i < maxIter && checked < count; i++) {
      if (minuteOk(d.getMinutes()) && hourOk(d.getHours()) && dayOk(d.getDate()) && monOk(d.getMonth() + 1) && wdOk(d.getDay())) {
        runs.push(new Date(d));
        checked++;
      }
      d.setMinutes(d.getMinutes() + 1);
    }
    return runs;
  }

  function fmtDate(d) {
    return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0') + ' ' + String(d.getHours()).padStart(2,'0') + ':' + String(d.getMinutes()).padStart(2,'0');
  }

  window.applyPreset = function(expr) {
    var parts = expr.split(' ');
    document.getElementById('minute').value = parts[0] || '*';
    document.getElementById('hour').value = parts[1] || '*';
    document.getElementById('day').value = parts[2] || '*';
    document.getElementById('month').value = parts[3] || '*';
    document.getElementById('weekday').value = parts[4] || '*';
    generateCron();
  };

  window.generateCron = function() {
    var min = document.getElementById('minute').value.trim() || '*';
    var hr = document.getElementById('hour').value.trim() || '*';
    var day = document.getElementById('day').value.trim() || '*';
    var mon = document.getElementById('month').value.trim() || '*';
    var wd = document.getElementById('weekday').value.trim() || '*';

    var err = document.getElementById('errorMsg');
    err.style.display = 'none';

    var minP = parseField(min, 0, 59);
    var hrP = parseField(hr, 0, 23);
    var dayP = parseField(day, 1, 31);
    var monP = parseField(mon, 1, 12);
    var wdP = parseField(wd, 0, 6);

    if (!minP || !hrP || !dayP || !monP || !wdP) {
      err.textContent = '⚠ 输入值超出范围，请检查：分钟(0-59)、小时(0-23)、日期(1-31)、月份(1-12)、星期(0-6)';
      err.style.display = 'block';
      return;
    }

    var expr = min + ' ' + hr + ' ' + day + ' ' + mon + ' ' + wd;
    var result = 'Cron: ' + expr + '\n';
    result += '说明: ' + describeCron(min, hr, day, mon, wd);

    document.getElementById('cronOutput').value = result;
    document.getElementById('descText').innerHTML = '<strong>含义：</strong>' + describeCron(min, hr, day, mon, wd);

    var runs = getNextRuns(min, hr, day, mon, wd, 5);
    var runsDiv = document.getElementById('nextRuns');
    if (runs.length > 0) {
      runsDiv.innerHTML = '<strong>接下来5次执行：</strong><br>' + runs.map(function(r) { return '· ' + fmtDate(r); }).join('<br>');
    }
  };

  window.clearAll = function() {
    document.getElementById('minute').value = '*';
    document.getElementById('hour').value = '*';
    document.getElementById('day').value = '*';
    document.getElementById('month').value = '*';
    document.getElementById('weekday').value = '*';
    document.getElementById('cronOutput').value = '';
    document.getElementById('descText').innerHTML = '自然语言解释将显示在这里';
    document.getElementById('nextRuns').innerHTML = '';
    document.getElementById('errorMsg').style.display = 'none';
  };

  window.copyResult = function() {
    var text = document.getElementById('cronOutput').value;
    if (!text) return;
    if (navigator.clipboard) {
      navigator.clipboard.writeText(text).then(function() {
        var btn = document.getElementById('copyOutput');
        btn.textContent = '已复制!';
        setTimeout(function() { btn.textContent = '复制'; }, 1500);
      });
    }
  };

  // Auto-generate on load with default values
  generateCron();
})();

tools.renderFn:
function(data, search) {
  var ip = search && search.trim() ? search.trim() : '';
  var html = '<div class=tool-card><h3>查询结果</h3>';
  if (!ip) {
    html += '<p id=ipResult style=color:#888;>正在查询您的 IP 地址...</p></div>';
    ip = '';
  } else {
    html += '<p id=ipResult style=color:#888;>正在查询 ' + ip + '...</p></div>';
  }
  var url = ip ? 'https://ipapi.co/' + ip + '/json/' : 'https://ipapi.co/json/';
  setTimeout(function(){
    fetch(url).then(function(r){return r.json();}).then(function(d){
      var el = document.getElementById('ipResult');
      if (el) {
        if (d.error) {
          el.outerHTML = '<p style=color:red;>查询失败：' + (d.reason||'无效的IP地址') + '</p>';
        } else {
          el.outerHTML = '<div><p><strong>IP：</strong>' + (d.ip||'未知') + '</p><p><strong>城市：</strong>' + (d.city||'未知') + '</p><p><strong>地区：</strong>' + (d.region||'未知') + '</p><p><strong>国家：</strong>' + (d.country_name||'未知') + '</p><p><strong>运营商：</strong>' + (d.org||'未知') + '</p></div>';
        }
      }
    }).catch(function(e){
      var el = document.getElementById('ipResult');
      if (el) el.outerHTML = '<p style=color:red;>查询失败，请稍后重试</p>';
    });
  }, 100);
  return html;
}
